#!/usr/bin/env python3
"""apply_booster_packs.py — inject booster-pack + card-back art into assets/assets.json.

  a933 = Silver booster pack (First Edition Portfolio)
  a934 = Gold booster pack   (Dean's List Portfolio)
  a935 = Card back           (shared, all pull cards)

Idempotent. Run from the repo root, THEN `python3 build.py`.
Stores RAW base64 (no data: prefix); build.py adds the inline prefix.
"""
import json, os, sys, base64

ASSETS = os.path.join("assets", "assets.json")

def raw_only(v):
    i = v.find("base64,")
    return v[i+7:] if i != -1 else v

NEW = {
    "a933": "",
    "a934": "",
    "a935": "",
}

def check(k, v):
    assert not v.startswith("data:"), f"{k}: value has a data: prefix (must be raw base64)"
    head = base64.b64decode(v[:16] + "===")
    assert head.startswith(b"\x89PNG\r\n\x1a\n"), f"{k}: not a PNG (bad magic bytes)"

if not os.path.exists(ASSETS):
    sys.exit(f"[apply] ERROR: {ASSETS} not found — run from the repo root.")

assets = json.load(open(ASSETS))
for k, v in NEW.items():
    v = raw_only(v)
    check(k, v)
    assets[k] = v
    print(f"[apply] wrote {k}  ({len(v)//1024} KB b64)")

# guard: simulate build substitution, assert no doubled prefix
for k in NEW:
    assert not assets[k].startswith("data:"), f"{k}: stored value still has data: prefix"
    assert "base64,data:" not in ("data:image/png;base64," + assets[k]), f"{k}: double-prefix detected"

json.dump(assets, open(ASSETS, "w"))
print(f"[apply] assets.json now holds {len(assets)} assets. Next: python3 build.py")
